final:
module JK_latch(  
    input J,  
    input K,  
    input reset_clk,  
    output reg Q  
);  
    always @(posedge reset_clk) begin  
        if (J && !K)  
            Q <= 1;  
        else if (!J && K)  
            Q <= 0;  
        else if (J && K)  
            Q <= ~Q;  
    end  
endmodule
